const Usage = (args: EmptyStateProps) => {
	switch (args.variant) {
		case 'L': {
			const { ...rest } = args;
			return <EmptyState {...rest} />;
		}

		case 'M': {
			const { ...rest } = args;
			return <EmptyState {...rest} />;
		}

		case 'S': {
			const { variant, title } = args;
			return <EmptyState variant={variant} title={title} />;
		}

		default: {
			return <></>;
		}
	}
};

