					value={inputValue}
					ref={register()}
				/>
				<ButtonTertiary icon="talend-refresh" onClick={() => setValue('apiKey', getUUID())}>
					Regenerate
				</ButtonTertiary>
			</Form.Row>
			<Form.Buttons>
				<ButtonPrimary type="submit" onClick={() => {}}>
					Submit
				</ButtonPrimary>
			</Form.Buttons>
		</Form>
	);
};

