	const allDrawers = {
		first: (
			<Drawer
				withTransition
				stacked
				title="Im stacked drawer 1"
				onCancelAction={{ label: 'Close', onClick: () => remove('first') }}
			>
				<h1>Hello drawer 1</h1>
				<p>You should not being able to read this because I'm first</p>
